-- -----------------------------------------------------
-- function BIN_TO_UUID
-- -----------------------------------------------------

USE `weighsoft`;
DROP function IF EXISTS `BIN_TO_UUID`;
SHOW WARNINGS;

DELIMITER $$
USE `weighsoft`$$
CREATE DEFINER=`weighsoft`@`%` FUNCTION `BIN_TO_UUID`(b BINARY(16), f BOOLEAN) RETURNS char(36) CHARSET utf8
    DETERMINISTIC
BEGIN
   DECLARE hexStr CHAR(32);
   SET hexStr = HEX(b);
   RETURN LOWER(CONCAT(
        IF(f,SUBSTR(hexStr, 9, 8),SUBSTR(hexStr, 1, 8)), '-',
        IF(f,SUBSTR(hexStr, 5, 4),SUBSTR(hexStr, 9, 4)), '-',
        IF(f,SUBSTR(hexStr, 1, 4),SUBSTR(hexStr, 13, 4)), '-',
        SUBSTR(hexStr, 17, 4), '-',
        SUBSTR(hexStr, 21)
    ));
END$$

DELIMITER ;
SHOW WARNINGS;

-- -----------------------------------------------------
-- function UUID_TO_BIN
-- -----------------------------------------------------

USE `weighsoft`;
DROP function IF EXISTS `UUID_TO_BIN`;
SHOW WARNINGS;

DELIMITER $$
USE `weighsoft`$$
CREATE DEFINER=`weighsoft`@`%` FUNCTION `UUID_TO_BIN`(uuid CHAR(36), f BOOLEAN) RETURNS binary(16)
    DETERMINISTIC
BEGIN
  RETURN UNHEX(CONCAT(
  IF(f,SUBSTRING(uuid, 15, 4),SUBSTRING(uuid, 1, 8)),
  SUBSTRING(uuid, 10, 4),
  IF(f,SUBSTRING(uuid, 1, 8),SUBSTRING(uuid, 15, 4)),
  SUBSTRING(uuid, 20, 4),
  SUBSTRING(uuid, 25))
  );
END$$

DELIMITER ;
SHOW WARNINGS;

-- -----------------------------------------------------
-- procedure users_Weighsoft_changes
-- -----------------------------------------------------

USE `weighsoft`;
DROP procedure IF EXISTS `users_Weighsoft_changes`;
SHOW WARNINGS;

DELIMITER $$
USE `weighsoft`$$
CREATE DEFINER=`root`@`%` PROCEDURE `users_Weighsoft_changes`(

	`sync_min_timestamp` bigint  ,
	`sync_scope_id` char (36)  
)
BEGIN
SELECT DISTINCT	`side`.`id`, 
	`base`.`firstname`, 
	`base`.`lastname`, 
	`base`.`contact_num`, 
	`base`.`email`, 
	`base`.`password`, 
	`base`.`role_id`, 
	`base`.`site_id`, 
	`base`.`workstations_id`, 
	`base`.`company_id`, 
	`base`.`token`, 
	`base`.`updated_at`, 
	`base`.`created_at`, 
	`base`.`fingerprint`, 
	`base`.`deleted_at`, 
	`side`.`sync_row_is_tombstone`, 
	`side`.`update_scope_id` as `sync_update_scope_id` 
FROM `users` `base`
RIGHT JOIN `users_tracking` `side` ON `base`.`id` = `side`.`id`
WHERE (
	`side`.`timestamp` > sync_min_timestamp
	AND (`side`.`update_scope_id` <> sync_scope_id OR `side`.`update_scope_id` IS NULL) 
);

END$$

DELIMITER ;
SHOW WARNINGS;

-- -----------------------------------------------------
-- procedure users_Weighsoft_delete
-- -----------------------------------------------------

USE `weighsoft`;
DROP procedure IF EXISTS `users_Weighsoft_delete`;
SHOW WARNINGS;

DELIMITER $$
USE `weighsoft`$$
CREATE DEFINER=`root`@`%` PROCEDURE `users_Weighsoft_delete`(

	`in_id` int(10) unsigned  ,
	`sync_scope_id` char (36)  ,
	`sync_force_write` int  ,
	`sync_min_timestamp` bigint  ,
	OUT `sync_row_count` int  
)
BEGIN

DECLARE ts BIGINT;
DECLARE t_update_scope_id VARCHAR(36);
SET ts = 0;
SELECT `timestamp`, `update_scope_id` FROM `users_tracking` WHERE `users_tracking`.`id` = `in_id` LIMIT 1 INTO ts, t_update_scope_id;
DELETE FROM `users` WHERE
`id` = `in_id`
AND (ts <= sync_min_timestamp OR ts IS NULL OR t_update_scope_id = sync_scope_id OR sync_force_write = 1);

SELECT ROW_COUNT() INTO sync_row_count;


IF (sync_row_count > 0) THEN
	UPDATE `users_tracking`
	SET `update_scope_id` = sync_scope_id, 
		 `sync_row_is_tombstone` = 1, 
		 `timestamp` = ROUND(UNIX_TIMESTAMP(CURRENT_TIMESTAMP(6)) * 10000), 
		 `last_change_datetime` = now() 
	WHERE `id` = `in_id`;
END IF;

END$$

DELIMITER ;
SHOW WARNINGS;

-- -----------------------------------------------------
-- procedure users_Weighsoft_deletemetadata
-- -----------------------------------------------------

USE `weighsoft`;
DROP procedure IF EXISTS `users_Weighsoft_deletemetadata`;
SHOW WARNINGS;

DELIMITER $$
USE `weighsoft`$$
CREATE DEFINER=`root`@`%` PROCEDURE `users_Weighsoft_deletemetadata`(

	`sync_row_timestamp` bigint  
)
BEGIN

DELETE FROM `users_tracking` WHERE `timestamp` < sync_row_timestamp;

END$$

DELIMITER ;
SHOW WARNINGS;

-- -----------------------------------------------------
-- procedure users_Weighsoft_initialize
-- -----------------------------------------------------

USE `weighsoft`;
DROP procedure IF EXISTS `users_Weighsoft_initialize`;
SHOW WARNINGS;

DELIMITER $$
USE `weighsoft`$$
CREATE DEFINER=`root`@`%` PROCEDURE `users_Weighsoft_initialize`(

	`sync_min_timestamp` bigint  
)
BEGIN
SELECT
	`base`.`id`
, 	`base`.`firstname`
, 	`base`.`lastname`
, 	`base`.`contact_num`
, 	`base`.`email`
, 	`base`.`password`
, 	`base`.`role_id`
, 	`base`.`site_id`
, 	`base`.`workstations_id`
, 	`base`.`company_id`
, 	`base`.`token`
, 	`base`.`updated_at`
, 	`base`.`created_at`
, 	`base`.`fingerprint`
, 	`base`.`deleted_at`
FROM `users` `base`
LEFT JOIN `users_tracking` `side` ON `base`.`id` = `side`.`id`
WHERE (
	(`side`.`timestamp` > sync_min_timestamp or sync_min_timestamp IS NULL));

END$$

DELIMITER ;
SHOW WARNINGS;

