-- -----------------------------------------------------
-- procedure users_Weighsoft_update
-- -----------------------------------------------------

USE `weighsoft`;
DROP procedure IF EXISTS `users_Weighsoft_update`;
SHOW WARNINGS;

DELIMITER $$
USE `weighsoft`$$
CREATE DEFINER=`root`@`%` PROCEDURE `users_Weighsoft_update`(

	`in_id` int(10) unsigned  ,
	`in_firstname` varchar(255)  ,
	`in_lastname` varchar(255)  ,
	`in_contact_num` varchar(255)  ,
	`in_email` varchar(255)  ,
	`in_password` varchar(60)  ,
	`in_role_id` int(10) unsigned  ,
	`in_site_id` int(10) unsigned  ,
	`in_workstations_id` int(10) unsigned  ,
	`in_company_id` int(10) unsigned  ,
	`in_token` varchar(255)  ,
	`in_updated_at` datetime  ,
	`in_created_at` datetime  ,
	`in_fingerprint` text  ,
	`in_deleted_at` datetime  ,
	`sync_scope_id` char (36)  ,
	`sync_force_write` int  ,
	`sync_min_timestamp` bigint  ,
	OUT `sync_row_count` int  
)
BEGIN
DECLARE `t_in_id` int(10) unsigned  ;
DECLARE ts BIGINT;
DECLARE t_update_scope_id VARCHAR(36);
SET ts = 0;
SELECT `id`, 
`timestamp`, `update_scope_id` FROM `users_tracking` 
WHERE `users_tracking`.`id` = `in_id` LIMIT 1 
INTO `t_in_id`,  ts, t_update_scope_id;

UPDATE `users`
SET  `firstname` = `in_firstname`
,  `lastname` = `in_lastname`
,  `contact_num` = `in_contact_num`
,  `email` = `in_email`
,  `password` = `in_password`
,  `role_id` = `in_role_id`
,  `site_id` = `in_site_id`
,  `workstations_id` = `in_workstations_id`
,  `company_id` = `in_company_id`
,  `token` = `in_token`
,  `updated_at` = `in_updated_at`
,  `created_at` = `in_created_at`
,  `fingerprint` = `in_fingerprint`
,  `deleted_at` = `in_deleted_at`
WHERE `id` = `in_id` AND (ts <= sync_min_timestamp OR ts IS NULL OR t_update_scope_id  = sync_scope_id OR sync_force_write = 1);

SELECT ROW_COUNT() INTO sync_row_count;
IF (sync_row_count = 0) THEN
	INSERT  INTO `users`
	(`id`, `firstname`, `lastname`, `contact_num`, `email`, `password`, `role_id`, `site_id`, `workstations_id`, `company_id`, `token`, `updated_at`, `created_at`, `fingerprint`, `deleted_at`)
	SELECT * FROM ( SELECT `in_id`, `in_firstname`, `in_lastname`, `in_contact_num`, `in_email`, `in_password`, `in_role_id`, `in_site_id`, `in_workstations_id`, `in_company_id`, `in_token`, `in_updated_at`, `in_created_at`, `in_fingerprint`, `in_deleted_at`) as TMP 
	WHERE ( `t_in_id` IS NULL )
	OR (ts <= sync_min_timestamp OR ts IS NULL OR t_update_scope_id = sync_scope_id OR sync_force_write = 1)
	LIMIT 1;

SELECT ROW_COUNT() INTO sync_row_count;

END IF;

IF (sync_row_count > 0) THEN
	UPDATE `users_tracking`
	SET `update_scope_id` = sync_scope_id, 
		 `sync_row_is_tombstone` = 0, 
		 `timestamp` = ROUND(UNIX_TIMESTAMP(CURRENT_TIMESTAMP(6)) * 10000), 
		 `last_change_datetime` = now() 
	WHERE `id` = `in_id`;
END IF;

END$$

DELIMITER ;
SHOW WARNINGS;

SET SQL_MODE=@OLD_SQL_MODE;
SET FOREIGN_KEY_CHECKS=@OLD_FOREIGN_KEY_CHECKS;
SET UNIQUE_CHECKS=@OLD_UNIQUE_CHECKS;
